/* Return the largest sum of any contiguous subarray in the vector x.
   Example:
   input: [−2, 1, −3, 4, −1, 2, 1, −5, 4]
   output: 6
*/

inline int maximumSubarray(std::vector<int> const& x) {
    // Kadane's algorithm – O(n) time, O(1) extra space.
    int best = std::numeric_limits<int>::lowest();
    int current = 0;
    for (int v : x) {
        current = std::max(v, current + v);
        best = std::max(best, current);
    }
    return best;
}
