inline void negateOddsAndHalveEvens(std::vector<int>& x)
{
    const std::size_t n = x.size();
    const int* src = x.data();
    int* dst   = x.data();

    /* Parallelize with OpenMP and use a simple pointer loop.
       The operations are independent, so no race conditions arise.
       The loop is perfectly vectorizable by the compiler. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        const int val = src[i];
        if ((val & 1) == 0)                 // even
            dst[i] = val >> 1;              // divide by 2 (shift is faster)
        else
            dst[i] = -val;                  // negate odd
    }
}
