{
    const std::size_t n = x.size();
    if (n == 0) return 0.0;        // safeguard against division by zero

    double sum = 0.0;

#if defined(_OPENMP)
    // Parallel accumulation using OpenMP reduction.
    #pragma omp parallel for reduction(+:sum)
    for (std::size_t i = 0; i < n; ++i) {
        sum += x[i];
