/* Return the product of the vector x with every odd indexed element inverted.
   i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
   Example:
   input: [4, 2, 10, 4, 5]
   output: 25
*/
inline double productWithInverses(std::vector<double> const& x) {
    // Parallel accumulation with multiplication reduction
    double result = 1.0;
    const size_t n = x.size();

    // Use OpenMP parallel for with a reduction on a double.
    // We split the loop into chunks to avoid frequent synchronization
    #pragma omp parallel for reduction(*:result) schedule(static)
    for (size_t i = 0; i < n; ++i) {
        // Compute the factor for this element: x[i] if i even, else 1/x[i]
        double f = (i & 1) ? (1.0 / x[i]) : x[i];
        result *= f;
    }
    return result;
}
