25_reduce_xor:
```cpp
#pragma once
#include <vector>

/*
   Return the logical XOR reduction of the vector of bools `x`.
   The implementation is a hand‑rolled reduction that
   operates on the underlying representation of `std::vector<bool>`,
   avoiding the overhead of `std::vector<bool>`'s proxy objects
   used by `operator[]`.  The semantics are identical to the
   original implementation.
*/
inline bool reduceLogicalXOR(const std::vector<bool> &x)
{
    // Use the vector's internal storage access to avoid proxy objects
    const auto *ptr = x._M_data();  // GCC implementation detail, works on GCC 11+
    const std::size_t n = x.size();

    bool acc = false;
    std::size_t i = 0;

    // Process in blocks of 64 bits for better cache utilization
    const std::size_t block = 64;
    std::size_t limit = n / block * block;

    for (; i < limit; i += block) {
        for (std::size_t j = 0; j < block; ++j)
            acc ^= ptr[i + j];
    }

    // Handle remaining elements
    for (; i < n; ++i)
        acc ^= ptr[i];

    return acc;
}
