        std::array<std::size_t, 256> localBins{};
        std::size_t n = image.size();

        // Distribute work among threads (reduction not used directly because
        // std::array is not trivially reducible).  We use a classic
        // parallel for with static scheduling.
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i)
