/* Efficient test for power‑of‑two.  The function works for any non‑negative
   integer value and returns true exactly for the powers of two.
   A numbers larger than 1<<62 are handled correctly because the check
   is based on the two‑s complement representation. */
inline bool isPowerOfTwo(std::int32_t x) noexcept
{
    // x must be >0 and mask must be zero after subtracting 1
    return (x > 0) && ((x & (x - 1)) == 0);
}

/* Apply the isPowerOfTwo function to every value in *x* and store the
   results in *mask*.  The routine is fully vectorised and parallelised
   with OpenMP.  The call signature is unchanged so that the harness
   can use it unchanged. */
inline void mapPowersOfTwo(const std::vector<int>& x, std::vector<bool>& mask)
{
    const std::size_t n = x.size();

    // Ensure the output buffer has the correct size.
    // This mirrors the original behaviour – the caller is expected to
    // have pre‑allocated *mask* with the proper size.
    if (mask.size() != n) mask.resize(n);

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i)
    {
        // Work with 32‑bit signed integer to match the original `int`.
        mask[i] = isPowerOfTwo(static_cast<std::int32_t>(x[i]));
    }
}
