#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/*
 * Compute the maximum degree in an undirected graph represented
 * by an `N x N` adjacency matrix stored row‑major in `A`.
 * Degree of a node is the sum of the corresponding row.
 * Complexity: O(N²) – the operation cannot be shortened,
 * but the loop is parallelised and use pointer arithmetic.
 *
 * The implementation preserves the exact behaviour of the original
 * function while being considerably faster on multi‑core machines.
 */
int maxDegree(std::vector<int> const& A, std::size_t N)
{
    const int* const data = A.data();
    int highestDegree = 0;

    #pragma omp parallel for reduction(max:highestDegree) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        int degree = 0;
        const int* row = data + i * N;           // pointer to the start of the row
        for (std::size_t j = 0; j < N; ++j)
            degree += row[j];                     // same as `data[i*N + j]`

        highestDegree = std::max(highestDegree, degree);
    }

    return highestDegree;
}
