struct Element {
    std::size_t index;
    double value;
};

/* Compute z = alpha * x + y where x and y are sparse vectors. Store the result in z.
   The routine is parallelised with OpenMP.  The input vectors x and y are assumed to be
   sorted by index (as in the original implementation).  The output vector z must be
   large enough to hold all indices used in x and y and should be initialised to zero
   by the caller.  The function preserves the exact numerical behaviour of the
   original serial algorithm. */
void sparseAxpy(double alpha, std::vector<Element> const& x,
                std::vector<Element> const& y, std::vector<double>& z) {
    // First add y – no conflicts because indices of y are unique within y.
    #pragma omp parallel for
    for (std::size_t i = 0; i < y.size(); ++i) {
        z[y[i].index] += y[i].value;
    }

    // Then add alpha * x – atomic addition to avoid race conditions if the same index
    // appears multiple times across x (which would violate the precondition but we
    // keep the original semantics safe anyway).
    #pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i) {
        #pragma omp atomic
        z[x[i].index] += alpha * x[i].value;
    }
}
