    int const nthreads = omp_get_max_threads();
    // Allocate thread‑local bin arrays
    std::vector<std::array<size_t,10>> local_bins(nthreads);
    for (auto &arr : local_bins) arr.fill(0);

    // Parallel accumulation – each thread writes to its own array
    #pragma omp parallel
