        auto &local = local_bins[t];
        #pragma omp for schedule(static)
        for (size_t i = 0; i < x.size(); ++i) {
            size_t bin = static_cast<size_t>(x[i]) / 10;   // 0‑9
            // values equal to 100 go into bin 10 → wrap to 9
            if (bin >= 10) bin = 9;
            local[bin] += 1;
        }
