/*
 * Compute the reverse prefix sum of the vector `x` into `output`.
 *
 * For each index `i` (0‑based),
 *   output[i] = x[n-1] + x[n-2] + … + x[n-1-i]
 *
 * Examples:
 *   x = [1, 7, 4, 6, 6, 2]
 *   output = [2, 8, 14, 18, 25, 26]
 *   x = [3, 3, 7, 1, -2]
 *   output = [-2, -1, 6, 9, 12]
 */
inline void reversePrefixSum(std::vector<int> const& x,
                             std::vector<int>& output)
{
    const std::size_t n = x.size();
    output.resize(n);

    int acc = 0;
    for (std::size_t i = 0; i < n; ++i) {
        acc += x[n - 1 - i];
        output[i] = acc;
    }
}
