#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Compute y = alpha * A * x + beta * y
 * A is an MxN sparse matrix in COO format.
 * x and y are vectors of length N (for x) and M (for y).
 */
inline void spmv(double alpha,
                 const std::vector<COOElement>& A,
                 const std::vector<double>& x,
                 double beta,
                 std::vector<double>& y,
                 std::size_t M,
                 std::size_t N)
{
    const std::size_t y_size = y.size();

    // Scale y by beta
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y_size; ++i) {
        y[i] *= beta;
    }

    // Accumulate contributions from A into y
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < A.size(); ++k) {
        const auto& e = A[k];
        if (e.row < M && e.column < N) {
            double tmp = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += tmp;
        }
    }
}
