    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const std::size_t n = x.size();
    if (n == 0) return;

    // Each thread will keep a private count array
    std::vector<std::array<std::size_t,4>> local(n > 0 ? 1 : 0);
    int threads = 8; // target number of threads
    omp_set_num_threads(threads);

