        for (std::size_t i = 0; i < n; ++i) {
            const double val = x[i];
            const double frac = val - static_cast<int>(val);
            if (frac < 0.25)      ++localBins[0];
            else if (frac < 0.5)  ++localBins[1];
            else if (frac < 0.75) ++localBins[2];
            else                  ++localBins[3];
