/* Union‑Find (Disjoint Set Union) structure with path compression
 * and union by rank.  It is used to merge all vertices that are
 * connected by an edge in the undirected graph represented by
 * the adjacency matrix A.
 */
struct DSU {
    std::vector<size_t> parent;
    std::vector<unsigned char> rank;   // small rank is enough for N <= 2^24

    explicit DSU(size_t n) : parent(n), rank(n, 0) {
        std::iota(parent.begin(), parent.end(), 0);
    }

    size_t find(size_t x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];   // path halving
            x = parent[x];
        }
        return x;
    }

    void unite(size_t a, size_t b) {
        a = find(a);
        b = find(b);
        if (a == b) return;
        if (rank[a] < rank[b]) std::swap(a, b);
        parent[b] = a;
        if (rank[a] == rank[b]) ++rank[a];
    }
};

/* Count the number of connected components in the undirected graph
 * defined by the adjacency matrix A (row‑major).  The implementation
 * uses a Union‑Find data structure and is fully deterministic,
 * preserving the exact behavior of the original recursive DFS.
 */
int componentCount(std::vector<int> const& A, size_t N) {
    // Fast path for empty graph
    if (N == 0) return 0;

    DSU dsu(N);

    // Iterate over upper triangle of the symmetric matrix and
    // union every pair of connected vertices.
    for (size_t i = 0; i < N; ++i) {
        size_t row_start = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[row_start + j] == 1) {
                dsu.unite(i, j);
            }
        }
    }

    // Count distinct roots
    std::vector<bool> seen(N, false);
    int components = 0;
    for (size_t i = 0; i < N; ++i) {
        size_t root = dsu.find(i);
        if (!seen[root]) {
            seen[root] = true;
            ++components;
        }
    }
    return components;
}
