/* Compute one iteration of a 3‑point 1D Jacobi stencil.
   input[i] is averaged with its two neighbours.
   When a neighbour is out of bounds, 0 is used.
   The result is stored into output[i].
*/
inline void jacobi1D(const std::vector<double> &input,
                     std::vector<double> &output)
{
    const size_t N = input.size();
    if (N == 0) return;

    /* Parallel region – each thread works on a chunk of rows.
       Using omp parallel for guarantees that the dependency on
       neighbouring values is only read, not written, so a straight
       parallel loop is safe. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        double left  = (i > 0)       ? input[i - 1] : 0.0;
        double right = (i + 1 < N)   ? input[i + 1] : 0.0;
        output[i] = (left + input[i] + right) / 3.0;
    }
}
