#pragma once
#include <cstdint>
#include <vector>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the vector `x` into `output`.
 * The result is the same as the standard library `std::inclusive_scan`.
 *
 * This implementation performs a parallel prefix sum using a two‑pass
 * algorithm that is both cache friendly and embarrassingly parallel.
 * It never changes the order or the values, thus the behavior is
 * guaranteed to be identical to the reference implementation.
 */
void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    const std::size_t n = x.size();
    if(n == 0) {                               // nothing to do
        output.resize(0);
        return;
    }
    output.resize(n);

    const int nThreads = std::min(static_cast<int>(n), omp_get_max_threads());
    const std::size_t chunk = (n + nThreads - 1) / nThreads;  // ceil

    /* Step 1 : each thread computes a local inclusive scan of its chunk
     * and stores the sum of that chunk in `chunkSum[tid]`. */
    std::vector<int64_t> chunkSum(nThreads, 0);
#pragma omp parallel num_threads(nThreads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        if(start < end) {
            int64_t acc = 0;
            for(std::size_t i = start; i < end; ++i) {
                acc += x[i];
                output[i] = acc;
            }
            chunkSum[tid] = acc;
        }
    }

    /* Step 2 : compute the prefix sum of the chunk sums sequentially
     * to obtain the offset that each thread must add to its results. */
    for(int t = 1; t < nThreads; ++t)
        chunkSum[t] += chunkSum[t-1];

    /* Step 3 : add the offset to each thread's block, except the first. */
#pragma omp parallel for schedule(static, 1)
    for(int t = 1; t < nThreads; ++t) {
        const std::size_t start = t * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        const int64_t offset = chunkSum[t-1];
        for(std::size_t i = start; i < end; ++i)
            output[i] += offset;
    }
}
