struct Point {
    double x, y;
};

/* Compute the squared Euclidean distance between two points.
   No sqrt is performed here to avoid unnecessary work. */
inline double dist2(Point const& a, Point const& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* Return the distance between the closest two points in the vector points.
   Example:
   input: [{2, 3}, {12, 30}, {40, 50}, {5, 1}, {12, 10}, {3, 4}]
   output: 1.41421
*/
double closestPair(std::vector<Point> const& points) noexcept {
    const std::size_t n = points.size();
    if (n < 2) {
        return 0.0;
    }

    double bestDistSq = std::numeric_limits<double>::max();

    /* Parallel brute–force search.
       The loop is split among threads; each thread keeps a local
       minimum which are then reduced to the global minimum. */
    #pragma omp parallel for schedule(static) reduction(min : bestDistSq)
    for (std::size_t i = 0; i < n - 1; ++i) {
        const Point& pi = points[i];
        for (std::size_t j = i + 1; j < n; ++j) {
            const double d2 = dist2(pi, points[j]);
            if (d2 < bestDistSq) {
                bestDistSq = d2;
            }
        }
    }

    return std::sqrt(bestDistSq);
}
