/* Set every cell's value to 1 if it has exactly one neighbor that's a 1. Otherwise set it to 0.
 * input and output are NxN grids of ints in row-major.
 */
inline void cellsXOR(const std::vector<int> &input, std::vector<int> &output, size_t N)
{
    const int stride = static_cast<int>(N);            // distance between rows
    const int *in  = input.data();
    int       *out = output.data();

    // Parallel over rows; each thread works on a distinct set of rows,
    // so there is no false‑sharing on the output buffer.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i)
    {
        const int base = i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j)
        {
            int count = 0;
            if (i > 0      && in[(i-1)*stride + j] == 1) ++count;
            if (i < static_cast<int>(N)-1 && in[(i+1)*stride + j] == 1) ++count;
            if (j > 0      && in[base + j-1] == 1) ++count;
            if (j < static_cast<int>(N)-1 && in[base + j+1] == 1) ++count;
            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
