#pragma once
#include <vector>
#include <algorithm>
#include <utility>
#include <cstddef>
#include <omp.h>

struct Point { double x, y; };

inline bool cmp_xy(const Point& a, const Point& b) noexcept {
    return (a.x < b.x) || (a.x == b.x && a.y < b.y);
}

inline double cross(const Point& o, const Point& a, const Point& b) noexcept {
    return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) { hull = points; return; }

    std::vector<Point> pts = points;                       // local copy for sorting
    std::sort(pts.begin(), pts.end(), cmp_xy);

    hull.resize(2 * n);                                     // pre‑allocate maximum size
    std::size_t k = 0;

    /* Lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0.0) --k;
        hull[k++] = pts[i];
    }

    /* Upper hull */
    for (std::size_t i = n-1, t = k+1; i > 0; --i) {
        while (k >= t && cross(hull[k-2], hull[k-1], pts[i-1]) <= 0.0) --k;
        hull[k++] = pts[i-1];
    }

    hull.resize(k-1);                // remove the duplicated start point
}
