#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/*
 * Optimised sparse matrix‑by‑matrix multiplication.
 *
 * Y = A * X
 *
 *   A : M × K sparse matrix in COO format
 *   X : K × N sparse matrix in COO format (output column index is the third field)
 *   Y : M × N dense matrix in row‑major order
 *
 * The implementation builds a lookup table of the non‑zero columns of X
 * and then updates Y only for those matching columns.  OpenMP parallelises
 * over the outer loop on the entries of A.  The dense matrix Y is accessed
 * row‑major, so within a thread the updates to distinct rows are
 * independent, minimising contention.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          const size_t M,
          const size_t K,
          const size_t N)
{
   // Prepare Y
   Y.assign(M * N, 0.0);

   /* Build X_row_map: for each row index, store all X entries with that row.
    * This replaces the inner linear scan over all X entries.
    */
   std::vector<std::vector<COOElement>> X_rows(K);
   for (const auto& xe : X) {
       X_rows[xe.row].push_back(xe);
   }

   /* Parallel over the non‑zero entries of A */
   #pragma omp parallel for schedule(guided)
   for (size_t i = 0; i < A.size(); ++i) {
       const auto& a = A[i];
       const size_t aRow = a.row;
       const size_t aCol = a.column;
       const double aVal = a.value;

       const auto& rowVec = X_rows[aCol];
       for (const auto& xe : rowVec) {
           const size_t col = xe.column;
           const double prod = aVal * xe.value;
           /* NB: The majority of updates are to different rows (aRow),
            * so write conflicts are rare.  If contention becomes a problem
            * replace the += with atomic updates or thread‑private buffers. */
           Y[aRow * N + col] += prod;
       }
   }
}
