#include <cmath>
#include <cstdint>
#include <omp.h>

/* Compute the DFT of a real‑valued sequence `x`.
 * The output real parts are written into `r` and the imaginary parts into `i`.
 * The implementation is a radix‑2 iterative Cooley‑Tukey FFT with
 * pre‑computed twiddle factors and a fast bit‑reversal permutation.
 * The routine preserves the exact behaviour of the reference implementation
 * while exploiting OpenMP for multi‑threading and avoiding extra copies.
 */
void fft(const std::vector<std::complex<double>>& x, std::vector<double>& r, std::vector<double>& i)
{
    const unsigned N = static_cast<unsigned>(x.size());
    if (N == 0) return;
    const unsigned m = static_cast<unsigned>(std::log2(static_cast<double>(N)));

    // Pre‑allocate workspace
    std::vector<std::complex<double>> work(N);
    std::copy(x.begin(), x.end(), work.begin());

    /* 1. Bit‑reversal permutation, done in parallel */
    #pragma omp parallel for schedule(static)
    for (unsigned a = 0; a < N; ++a) {
        unsigned b = a;
        // Reverse lower 16 bits
        b = ((b >> 16) | (b << 16)) & 0xFFFFFFFF;
        // Reverse 4‑bit groups
        b = (((b & 0xF0F0F0F0) >> 4) | ((b & 0x0F0F0F0F) << 4));
        b = (((b & 0xCCCCCCCC) >> 2) | ((b & 0x33333333) << 2));
        b = (((b & 0xAAAAAAAA) >> 1) | ((b & 0x55555555) << 1));
        // Keep only m bits
        b >>= (32 - m);
        if (b > a) std::swap(work[a], work[b]);
    }

    /* 2. Pre‑compute twiddle factors for each stage */
    std::vector<std::complex<double>> twiddle(m);
    const double pi = std::acos(-1.0);
    for (unsigned stage = 0; stage < m; ++stage) {
        const double angle = -pi / static_cast<double>(1U << stage);
        twiddle[stage] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    /* 3. Iterative radix‑2 butterfly stages */
    unsigned half = 1;
    for (unsigned stage = 0; stage < m; ++stage, half <<= 1) {
        const std::complex<double> W = twiddle[stage];
        const unsigned full = half << 1;
        #pragma omp parallel for schedule(static)
        for (unsigned k = 0; k < half; ++k) {
            const std::complex<double> T = std::exp(std::complex<double>(0.0, -k * pi / static_cast<double>(half)));
            for (unsigned j = k; j < N; j += full) {
                unsigned l = j + half;
                std::complex<double> t = work[j] - work[l];
                work[j] += work[l];
                work[l] = t * T;
            }
        }
    }

    /* 4. Copy result into output arrays */
    #pragma omp parallel for schedule(static)
    for (unsigned j = 0; j < N; ++j) {
        r[j] = work[j].real();
        i[j] = work[j].imag();
    }
}
