#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(
    const std::vector<COOElement>& A,
    const std::vector<double>& b,
    std::vector<double>& x,
    size_t N)
{
    // Use a flat array to avoid vector of vectors overhead
    std::vector<double> mat(N * N, 0.0);
    std::vector<double> b_copy = b;

    /* Fill the matrix from COO representation in parallel
       (there are no conflicts because each element is unique)
    */
#pragma omp parallel for schedule(static, 256)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        mat[e.row * N + e.column] = e.value;
    }

    x.assign(N, 0.0);

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* Find pivot row */
        double maxEl = std::fabs(mat[i * N + i]);
        size_t maxRow = i;
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::fabs(mat[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }

        /* Swap rows (including RHS) */
        for (size_t k = i; k < N; ++k) {
            std::swap(mat[maxRow * N + k], mat[i * N + k]);
        }
        std::swap(b_copy[maxRow], b_copy[i]);

        /* Eliminate entries below the pivot */
        for (size_t k = i + 1; k < N; ++k) {
            double c = -mat[k * N + i] / mat[i * N + i];
            // NOTE: we can unroll the inner loop a bit
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    mat[k * N + j] = 0.0;
                } else {
                    mat[k * N + j] += c * mat[i * N + j];
                }
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* Back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / mat[i * N + i];
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= mat[k * N + i] * x[i];
        }
    }
}
