// Computes twice the signed area of triangle (a,b,c)
// (positive if the points are counter‑clockwise)
inline double signedArea2(const Point& a, const Point& b, const Point& c) {
    return a.x*(b.y - c.y) + b.x*(c.y - a.y) + c.x*(a.y - b.y);
}

// Returns the minimal area of any triangle formed by the given points.
// The area is always non‑negative. In the original specification the
// triangle area is halved; we do the division once at the end.
inline double smallestArea(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    const double INF = std::numeric_limits<double>::max();
    double best = INF;

    // parallelise with OpenMP – collapse the three nested loops.
    #pragma omp parallel for collapse(3) schedule(static)
    for (size_t i = 0; i < n - 2; ++i) {
        const Point* pi = &points[i];
        for (size_t j = i + 1; j < n - 1; ++j) {
            const Point* pj = &points[j];
            for (size_t k = j + 1; k < n; ++k) {
                double a2 = signedArea2(*pi, *pj, points[k]); // 2 * signed area
                if (a2 == 0) {                                 // points are collinear
                    best = 0.0;
                    #pragma omp cancel for
                    break;
                }
                double area = std::abs(a2) * 0.5; // area = |a2|/2
                if (area < best) {
                    best = area;
                    if (best == 0.0) {                // cannot get smaller than zero
                        #pragma omp cancel for
                        break;
                    }
                }
            }
        }
    }
    return best;
}
