/*
 * Compute the rank (index in the sorted array) of each element in x.
 * The result is stored in `ranks_`.  The function preserves the exact
 * behaviour of the reference implementation.
 */
inline void ranks(std::vector<float> const& x, std::vector<std::size_t>& ranks_)
{
    const std::size_t n = x.size();

    /* ---------- 1. prepare a permutation of indices  ---------- */
    std::vector<std::size_t> indices(n);
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
        indices[i] = i;

    /* ---------- 2. sort the indices according to the values  ---------- */
    std::sort(indices.begin(), indices.end(),
              [&x](std::size_t i1, std::size_t i2)
              { return x[i1] < x[i2]; });

    /* ---------- 3. write the ranks back to the output array  ---------- */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
        ranks_[indices[i]] = i;
}
