#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// Optimised discrete Fourier transform – identical semantics to the original.
// -----------------------------------------------------------------------------
//   input : vector of N real samples
//   output: vector of N complex numbers = DFT(x)
// -----------------------------------------------------------------------------

void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output)
{
    const size_t N = x.size();
    if (N == 0) { output.clear(); return; }

    // Resize and zero‑initialize the output vector
    output.resize(N);
    std::memset(output.data(), 0, N * sizeof(std::complex<double>));

    // Pre‑compute the twiddle factors: W[n][k] = exp(-i 2π n k / N)
    // We keep them real and imaginary parts in separate contiguous arrays
    std::vector<double> twr( N * N );   // real parts
    std::vector<double> twi( N * N );   // imaginary parts
    const double two_pi = 2.0 * M_PI;
    for (size_t n = 0; n < N; ++n) {
        for (size_t k = 0; k < N; ++k) {
            double angle = two_pi * n * k / N;
            twr[n * N + k] =  std::cos(angle);
            twi[n * N + k] = -std::sin(angle);
        }
    }

    // Main DFT loop – parallelised over the output indices k
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < static_cast<int>(N); ++k) {
        double re = 0.0, im = 0.0;
        const size_t idx = k;
        const double* const xr = x.data();
        const double* const wre = twr.data() + idx;
        const double* const wim = twi.data() + idx;

        // Unroll a few iterations to reduce loop overhead
        size_t n = 0;
        for (; n + 3 < N; n += 4) {
            double a0 = xr[n  ] * wre[n  ] - xr[n  ] * wim[n  ];
            double b0 = xr[n  ] * wim[n  ] + xr[n  ] * wre[n  ];
            double a1 = xr[n+1] * wre[n+1] - xr[n+1] * wim[n+1];
            double b1 = xr[n+1] * wim[n+1] + xr[n+1] * wre[n+1];
            double a2 = xr[n+2] * wre[n+2] - xr[n+2] * wim[n+2];
            double b2 = xr[n+2] * wim[n+2] + xr[n+2] * wre[n+2];
            double a3 = xr[n+3] * wre[n+3] - xr[n+3] * wim[n+3];
            double b3 = xr[n+3] * wim[n+3] + xr[n+3] * wre[n+3];
            re += a0 + a1 + a2 + a3;
            im += b0 + b1 + b2 + b3;
        }
        for (; n < N; ++n) {
            re += xr[n] * wre[n];
            im += xr[n] * wim[n];
        }
        output[k] = std::complex<double>(re, im);
    }
}
