```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <algorithm> // for std::fill
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
   Factorize the sparse matrix A into A = LU where L is a unit lower triangular
   matrix and U is an upper triangular matrix.
   A is a sparse NxN matrix stored in COO format.  The result is stored in
   single‑dimensional row‑major arrays `L` and `U` (size N*N).
   The implementation keeps the original algorithm but removes the intermediate
   2‑D full matrix and exploits OpenMP parallelism over the inner column loop.
*/
void luFactorize(const std::vector<COOElement>& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 std::size_t N)
{
    // Linear full matrix (row major).  Dimensions are small enough for a dense
    // representation while still being more cache friendly than a vector of vectors.
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A) {
        fullA[e.row * N + e.column] = e.value;
    }

    // Allocate or resize L and U to hold N*N elements
    if (L.size() != N * N) L.assign(N * N, 0.0);
    if (U.size() != N * N) U.assign(N * N, 0.0);

    for (std::size_t i = 0; i < N; ++i) {
        /* Parallel over columns j.  The two branches (U and L) are independent
           for a fixed row i, so a single parallel for is sufficient.  We use
           static scheduling because the workloads are uniform. */
#pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < N; ++j) {
            double valU = 0.0;
            double valL = 0.0;

            if (j >= i) {
                valU = fullA[i * N + j];
                for (std::size_t k = 0; k < i; ++k) {
                    valU -= L[i * N + k] * U[k * N + j];
                }
                U[i * N + j] = valU;
            }

            if (i > j) {
                valL = fullA[i * N + j];
                for (std::size_t k = 0; k < j; ++k) {
                    valL -= L[i * N + k] * U[k * N + j];
                }
                L[i * N + j] = valL / U[j * N + j];
            }
        }
        // unit diagonal for L
        L[i * N + i] = 1.0;
    }
}
