#include <omp.h>

/*
 * Matrix‑vector product: y = A * x
 * A is stored in row-major order (M x N).
 * x has N elements, y has M elements.
 * 
 * The implementation is fully parallel, cache-aware and keeps the exact
 * numeric semantics of the reference implementation.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Ensure there is work to do.
    if (M == 0 || N == 0 || A.empty() || x.empty() || y.empty()) return;

    // Block size tuned empirically for a typical L1/L2 layout (changeable).
    constexpr std::size_t BLOCK_SIZE = 64;

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        std::size_t j = 0;
        // Unroll one block at a time, which improves cache locality.
        for (; j + BLOCK_SIZE <= N; j += BLOCK_SIZE) {
            const double* aRow = &A[i * N + j];
            const double* xptr = &x[j];
            // Inner block loop unrolled (simple unrolling factor of 4).
            for (std::size_t k = 0; k < BLOCK_SIZE; k += 4) {
                sum += aRow[k + 0] * xptr[k + 0];
                sum += aRow[k + 1] * xptr[k + 1];
                sum += aRow[k + 2] * xptr[k + 2];
                sum += aRow[k + 3] * xptr[k + 3];
            }
        }
        // Tail: remaining columns
        for (; j < N; ++j) {
            sum += A[i * N + j] * x[j];
        }
        y[i] = sum;
    }
}
