#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* Edge kernel: 3x3 matrix */
static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* Convolve with the edge kernel.
 * The input and output are NxN monochrome images stored in row-major order.
 * The operation is performed in-place: imageOut is written with the result.
 * The function is safe for all NxN, clipping the result to [0,255].
 */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int>& imageOut,
                    size_t N) noexcept
{
    // Fast access pointers
    const int *in  = imageIn.data();
    int       *out = imageOut.data();

    const size_t stride = N;

    /* Parallelize over rows. Each row is independent. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int* inRow   = in + i * stride;
        int*       outRow  = out + i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            /* Kernel 3x3: offset -1, 0, 1 for both axes. */
            // row -1
            if (i > 0) {
                const int* p = inRow - stride;
                sum += p[j-1] * edgeKernel[0][0];  // (i-1,j-1)
                sum += p[j  ] * edgeKernel[0][1];  // (i-1,j)
                sum += p[j+1] * edgeKernel[0][2];  // (i-1,j+1)
            }
            // row 0
            sum += inRow[j-1] * edgeKernel[1][0];
            sum += inRow[j  ] * edgeKernel[1][1];
            sum += inRow[j+1] * edgeKernel[1][2];
            // row +1
            if (i + 1 < static_cast<int>(N)) {
                const int* p = inRow + stride;
                sum += p[j-1] * edgeKernel[2][0];
                sum += p[j  ] * edgeKernel[2][1];
                sum += p[j+1] * edgeKernel[2][2];
            }

            /* Clip to [0,255] */
            outRow[j] = static_cast<int>(std::min(255, std::max(0, sum)));
        }
    }
}
