#pragma once
#include <vector>
#include <omp.h>

/*  
   LU factorization without pivoting. 
   For every column k this routine stores the multipliers in A[i*N + k]
   (the L‑part) and overwrites the upper part with U. The algorithm
   is identical to the original reference implementation.
*/
inline void luFactorize(std::vector<double> &A, size_t N)
{
    const double *Arow;          // read‑only row pointer
    const double *Arowk;         // reference row k
    double *Ai;                  // write pointer for row i
    double aik;                  // A[i][k] after division by pivot
    const size_t Ncol = N;

    for (size_t k = 0; k < N; ++k)
    {
        /* locate the pivot element once */
        double Akk = A[k * Ncol + k];
        Arowk = &A[k * Ncol];                 // pivot row k

        /* the rows below k can be processed in parallel */
        #pragma omp parallel for schedule(static)
        for (long long i = static_cast<long long>(k) + 1; i < static_cast<long long>(N); ++i)
        {
            long long idxik = i * Ncol + k;   // index of A[i][k]
            aik = A[idxik] / Akk;             // factor
            Ai  = &A[i * Ncol];               // row i

            Ai[k] = aik;                      // store multiplier

            /* update the trailing sub‑matrix row */
            const double *const cross = Arowk + k + 1;
            double *const second  = Ai + k + 1;
            const long long len = Ncol - k - 1;
            #pragma ivdep
            for (long long j = 0; j < len; ++j)
                second[j] -= aik * cross[j];
        }
    }
}
