#pragma once
#include <vector>
#include <omp.h>

/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix in row-major order.  x and b contain N elements each.
 * The implementation preserves the original algorithmic semantics (no pivoting)
 * but is reorganised for better performance on a modern x86‑64 machine.
 */
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N) {
    /* Make local copies – the solver mutates the matrix and RHS. */
    std::vector<double> a = A;
    std::vector<double> rhs = b;

    /* === Gaussian elimination (forward pass) ========================== */
    for (size_t i = 0; i + 1 < N; ++i) {
        double pivot = a[i * N + i];
        if (pivot == 0.0) {            // preserve original early exit
            return;
        }
        /* Parallelise the elimination of rows below the pivot row. */
#pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            double factor = a[j * N + i] / pivot;
            double *row_j = &a[j * N];
            double *row_i = &a[i * N];
            for (size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            rhs[j] -= factor * rhs[i];
        }
    }

    /* === Back substitution (serial – small critical region) ========= */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double *row_i = &a[i * N];
        for (size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (rhs[i] - sum) / a[i * N + i];
    }
}
