```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

inline double distance(const Point& p1, const Point& p2)
{
    return std::hypot(p2.x - p1.x, p2.y - p1.y);
}

// Return the perimeter of the smallest convex polygon that contains all the points.
inline double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Work on a copy that can be sorted
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    auto cross = [](const Point& a, const Point& b, const Point& c) {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // Upper‑bound size is 2*n – 1
    std::vector<Point> hull;
    hull.reserve(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        if (k == hull.size())
            hull.push_back(sorted[i]);
        else
            hull[k++] = sorted[i];
    }

    // Build upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n; i-- > 0;) {
        while (k >= t && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        if (k == hull.size())
            hull.push_back(sorted[i]);
        else
            hull[k++] = sorted[i];
    }

    // Subtract the duplicated first point
    if (!hull.empty()) hull.resize(k - 1);

    // Compute perimeter in parallel
    double perimeter = 0.0;
    #pragma omp parallel for reduction(+:perimeter)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(hull.size()); ++i) {
        const Point& p1 = hull[i];
        const Point& p2 = hull[(i + 1) % hull.size()];
        perimeter += distance(p1, p2);
    }

    return perimeter;
}
