inline std::size_t findLastShortBook(std::vector<Book> const& books) {
    // Use signed type for the index to allow a sentinel value of -1.
    std::ptrdiff_t last = -1;

    // Parallel reduction for the maximum index that satisfies the condition.
    #pragma omp parallel for reduction(max:last)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(books.size()); ++i) {
        if (books[static_cast<std::size_t>(i)].pages < 100) {
            // i is always non‑negative, so it participates in the max
            // reduction.
            if (i > last) {
                last = i;
            }
        }
    }

    return (last == -1) ? books.size() : static_cast<std::size_t>(last);
}
