#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   A cell is 1 if it is alive and 0 if it is dead.
   If a live cell has fewer than 2 live neighbors then it dies.
   If a live cell has 2 or 3 live neighbors then it lives on.
   If a live cell has more than 3 live neighbords then it dies.
   If a cell is dead and has exactly 3 live neighbors then it becomes alive.
   `input` and `output` are NxN grids stored in row-major.
*/
inline void gameOfLife(std::vector<int> const& input, std::vector<int> &output, size_t N) {
    const int* src = input.data();
    int* dst = output.data();
    size_t total = N * N;

    /* Parallelised outer loop. Each iteration works on a single cell
       and writes the result to the corresponding position in `output`.
    */
#pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < total; ++idx) {
        size_t i = idx / N;
        size_t j = idx % N;

        int sum = 0;

        /* top row */
        if (i > 0) {
            sum += src[(i - 1) * N + j];
            if (j > 0)        sum += src[(i - 1) * N + (j - 1)];
            if (j + 1 < N)    sum += src[(i - 1) * N + (j + 1)];
        }
        /* bottom row */
        if (i + 1 < N) {
            sum += src[(i + 1) * N + j];
            if (j > 0)        sum += src[(i + 1) * N + (j - 1)];
            if (j + 1 < N)    sum += src[(i + 1) * N + (j + 1)];
        }
        /* left & right neighbours */
        if (j > 0)      sum += src[i * N + (j - 1)];
        if (j + 1 < N)  sum += src[i * N + (j + 1)];

        int cur = src[i * N + j];
        /* Apply the Game of Life rules */
        if (cur == 1) {
            dst[idx] = (sum == 2 || sum == 3) ? 1 : 0;
        } else {
            dst[idx] = (sum == 3) ? 1 : 0;
        }
    }
}
