```cpp
#pragma once
#include <cmath>
#include <complex>
#include <vector>
#include <algorithm>
#include <numeric>
#include <cstdint>
#include <iomanip>
#include <iostream>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

/* -------------------------------------------------------
   In‑place radix‑2 iterative FFT (bit‑reversal + butterfly)
   --------------------------------------------------------------------*/
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N < 2) return;
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    /* --------- step 1 : bit‑reversal permutation --------- */
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t b = i;
        // reverse only the lower logN bits
        b = ((b & 0xaaaaaaaa) >> 1) | ((b & 0x55555555) << 1);
        b = ((b & 0xcccccccc) >> 2) | ((b & 0x33333333) << 2);
        b = ((b & 0xf0f0f0f0) >> 4) | ((b & 0x0f0f0f0f) << 4);
        b = ((b & 0xff00ff00) >> 8) | ((b & 0x00ff00ff) << 8);
        b = ((b >> 16) | (b << 16));
        rev[i] = b >> (32 - logN);
    }

    /* do the permutation only once */
#pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        if (rev[i] > i) std::swap(x[i], x[rev[i]]);

    /* --------- step 2 : iterative butterfly pass --------- */
    std::vector<std::complex<double>> twiddle(N/2);
    for (std::size_t m = 1, p = 1; p < N; m <<= 1, ++p)
    {
        const double angle = -M_PI / static_cast<double>(m);
        const std::complex<double> w_m = std::polar(1.0, angle);   // exp(-i*2π/(2*m))
        std::complex<double> w = 1.0;
        for (std::size_t j = 0; j < m; ++j, w *= w_m)
            twiddle[j] = w;                                       // precompute

        /* process all sub‑sequences in parallel */
#pragma omp parallel for
        for (std::size_t k = 0; k < N; k += 2 * m)
        {
            for (std::size_t j = 0; j < m; ++j)
            {
                const std::size_t idx1 = k + j;
                const std::size_t idx2 = idx1 + m;
                const std::complex<double> t = x[idx2] * twiddle[j];
                x[idx2] = x[idx1] - t;
                x[idx1] += t;
            }
        }
    }
}

/* -------------------------------------------------------
   Inverse FFT: conjugate → forward FFT → conjugate → scale
   ---------------------------------------------------- */
inline void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // 1. conjugate
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // 2. forward FFT
    fft_helper(x);

    // 3. conjugate again
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // 4. scale by 1/N
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
        x[i] *= invN;
}
