#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Compute one iteration of a 5‑point 2D Jacobi stencil on `input`.
 * The result is written to `output`. Both arrays are N×N in row‑major
 * order. Boundary values outside the domain are treated as zero.
 *
 * This implementation is heavily optimised:
 *   - The work is distributed among threads using OpenMP parallel for
 *   - The boundary rows/columns are processed separately from the
 *     interior to avoid unnecessary bounds checks.
 *   - Pointer arithmetic is used for maximum cache friendliness.
 *   - The compiler will vectorise the inner loop where possible.
 */
inline void jacobi2D(const std::vector<double>& input,
                     std::vector<double>& output,
                     const std::size_t N)
{
    const std::size_t stride = N;
    const double inv5 = 1.0 / 5.0;

    // Pre‑compute the chunk sizes for the interior region.
    // Row and column indices.
    const std::size_t first = 1;
    const std::size_t last  = N - 1;

    // Handle top row (i = 0) – only lower and horizontal neighbors exist.
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t idx = j;
        double sum = input[idx];
        if (j > 0)              sum += input[idx - 1];
        if (j < N-1)            sum += input[idx + 1];
        if (N > 1)              sum += input[idx + stride];   // i+1 row
        output[idx] = sum * inv5;
    }

    // Handle bottom row (i = N-1)
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t idx = (N-1)*stride + j;
        double sum = input[idx];
        if (j > 0)              sum += input[idx - 1];
        if (j < N-1)            sum += input[idx + 1];
        if (N > 1)              sum += input[idx - stride];   // i-1 row
        output[idx] = sum * inv5;
    }

    // Handle left and right columns of the interior rows.
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = first; i < last; ++i) {
        std::size_t idx = i*stride;          // left column
        double sum = input[idx];
        if (i > 0)               sum += input[idx - stride];   // top
        if (i < N-1)             sum += input[idx + stride];   // bottom
        if (N > 1)               sum += input[idx + 1];        // right
        output[idx] = sum * inv5;

        idx = (i+1)*stride - 1;                // right column
        sum = input[idx];
        if (i > 0)               sum += input[idx - stride];   // top
        if (i < N-1)             sum += input[idx + stride];   // bottom
        if (N > 1)               sum += input[idx - 1];        // left
        output[idx] = sum * inv5;
    }

    // Handle the interior sub‑matrix (i=1..N-2, j=1..N-2)
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = first; i < last; ++i) {
        std::size_t base = i * stride;
        for (std::size_t j = first; j < last; ++j) {
            std::size_t idx = base + j;
            double sum = input[idx]
                       + input[idx - stride]          // top
                       + input[idx + stride]          // bottom
                       + input[idx - 1]               // left
                       + input[idx + 1];              // right
            output[idx] = sum * inv5;
        }
    }
}
