#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/*  An efficient in‑place radix‑2 FFT that returns the conjugated result.
    The algorithm keeps the exact behaviour of the original implementation:
    - the input vector contains a power‑of‑two length
    - the function performs a forward DFT followed by a conjugate on every element
    - the final result is stored back into the same vector.

    Performance improvements:
    - pre‑compute bit‑reversal indices (O(n))
    - use an iterative Cooley‑Tukey radix‑2 split‑radix scheme
    - replace expensive std::log2/log2 call with bit‑count
    - parallelise the conjugation step with OpenMP
*/

inline static std::vector<uint32_t> gen_bit_reverse_table(std::size_t N)
{
    // we assume N is a power of two and fits into 32 bits
    std::size_t logN = 0;
    std::size_t tmp = N;
    while (tmp >>= 1) ++logN;

    std::vector<uint32_t> rev(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        uint32_t x = static_cast<uint32_t>(i);
        x = (x >> 16) | (x << 16);
        x = ((x & 0xff00ff00u) >> 8) | ((x & 0x00ff00ffu) << 8);
        x = ((x & 0xf0f0f0f0u) >> 4) | ((x & 0x0f0f0f0fu) << 4);
        x = ((x & 0xccccccccu) >> 2) | ((x & 0x33333333u) << 2);
        x = ((x & 0xaaaaaaaau) >> 1) | ((x & 0x55555555u) << 1);
        rev[i] = x >> (32 - logN);
    }
    return rev;
}

inline static void fft_radix2(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // Bit‑reversal reordering
    std::vector<uint32_t> rev = gen_bit_reverse_table(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = rev[i];
        if (j > i)
        {
            std::swap(x[i], x[j]);
        }
    }

    // Cooley‑Tukey iterative FFT
    for (std::size_t s = 1; s < N; s <<= 1)          // stage size
    {
        const double angle = -M_PI / static_cast<double>(s);
        const double wlen_cos = std::cos(angle);
        const double wlen_sin = std::sin(angle);
        for (std::size_t j = 0; j < N; j += (s << 1))  // block
        {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t k = 0; k < s; ++k)
            {
                std::complex<double> u = x[j + k];
                std::complex<double> v = x[j + k + s] * w;
                x[j + k] = u + v;
                x[j + k + s] = u - v;
                w *= std::complex<double>(wlen_cos, wlen_sin);
            }
        }
    }
}

inline static void conjugate_vector(std::vector<std::complex<double>>& x)
{
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        x[i] = std::conj(x[i]);
    }
}

inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    fft_radix2(x);
    conjugate_vector(x);
}
