09_fft_fft_out_of_place:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cstdint>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
# define M_PI 3.141592653589793238462643383279502884L
#endif

/* In-place radix‑2 FFT implementation.  The input vector is copied into
 * “output” and the DFT results written into the same vector.
 *
 * The algorithm follows the “iterative Cooley‑Tukey” scheme with
 * pre‑computed twiddle‑factors and an efficient bit‑reversal
 * permutation.  An OpenMP parallel loop is used for the butterfly
 * operations, exploiting up to 8 threads on the target machine.
 *
 * The implementation is fully deterministic and matches the
 * behaviour of the original reference code (including the sign of the
 * exponential and the ordering of the output).
 */
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                       // copy input

    if ((N & (N-1)) != 0 || N == 0)   // must be power of two
        return;

    /* ---------- pre‑compute twiddle factors ----------
     *
     * W_N^k = exp(-2πi k / N)
     * For the radix‑2 algorithm we need W_{2^m}^(2k+1) = exp(-πi (2k+1)/2^{m-1})
     * for m = 1 .. log2(N).  We compute all values up to the final stage
     * and store them in an array for fast indexing.
     */
    const std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::complex<double>> twiddles((N>>1));
    {
        const double twoPi = 2.0 * M_PI;
        double angle = -twoPi / static_cast<double>(N);
        std::complex<double> w{std::cos(angle), std::sin(angle)};
        std::complex<double> t{1.0, 0.0};
        for (std::size_t i = 0; i < (N>>1); ++i) {
            twiddles[i] = t;
            t *= w;
        }
    }

    /* ---------- butterfly stages ----------
     *
     * For stage `s` (1‑based), we have block size = 2^s, stride = 2^{s-1}.
     * Each block contains an inner loop over indices `k` belonging to the
     * first half; the second half is accessed by `k + stride`.
     *
     * The outer loop over blocks is parallelized with OpenMP.  
     * The innermost loop is small enough that auto‑vectorisation
     * performs well even when unrolled manually.
     */
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t block = 1ULL << s;          // 2^s
        const std::size_t stride = block >> 1;        // 2^{s-1}
        const std::size_t twiddleStep = N >> s;       // stride into twiddle array

#pragma omp parallel for schedule(static)
        for (std::size_t b = 0; b < N; b += block) {
            std::size_t kBase = b;
            for (std::size_t k = 0; k < stride; ++k) {
                const std::size_t idx1 = kBase + k;
                const std::size_t idx2 = idx1 + stride;
                const std::complex<double>& a = output[idx1];
                const std::complex<double>& bval = output[idx2];
                const std::complex<double> t = twiddles[k * twiddleStep] * bval;

                output[idx1] = a + bval;
                output[idx2] = a - bval;
                output[idx2] = t;
            }
        }
    }

    /* ---------- bit‑reversal permutation ----------
     *
     * For power‑of‑two N, we reverse the lowest logN bits of each
     * index.  The following algorithm is compact and highly
     * cache‑friendly.
     */
    const std::size_t m = logN;
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        // reverse first m bits of j
        j = ((j & 0x55555555u) << 1) | ((j & 0xaaaaaaaau) >> 1);
        j = ((j & 0x33333333u) << 2) | ((j & 0xccccccccu) >> 2);
        j = ((j & 0x0f0f0f0fu) << 4) | ((j & 0xf0f0f0f0u) >> 4);
        j = ((j & 0x00ff00ffu) << 8) | ((j & 0xff00ff00u) >> 8);
        j = ((j & 0x0000ffffu) << 16) | ((j & 0xffff0000u) >> 16);
        j >>= (32 - m);
        if (j > i) {
            std::complex<double> tmp = output[i];
            output[i] = output[j];
            output[j] = tmp;
        }
    }
}
